interface.signature:
interface ApiEndpointOptions {
  summary: string;
  type?: Type<any>;
  status?: number;
  consumes?: string; // 'application/json' | 'multipart/form-data'
  bodySchema?: SchemaObject; // NEW: for ApiBody integration
  isArray?: boolean;
  isPaginated?: boolean;
  isPublic?: boolean;
}

interface NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any>;
}

class I18nService {
  t(key: string, options?: any): string;
}

// Success Response
{
  success: true,
  status: 200 | 201 | 204,
  data: T | T[],
  count?: number,  // Only for paginated
  message: string
}

// Paginated Input Pattern (from service)
{
  items: T[],
  count: number
}
